    fn new(size: usize) -> Self {
        let parent = (0..size).map(|i| i).collect::<Vec<_>>();
        let rank = vec![1; size];
        DSU { parent, rank }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
